code = """import json
import re

# Access the data from storage variables
mit_packages = locals()['var_functions.query_db:56']
project_mappings = locals()['var_functions.query_db:46']
project_info = locals()['var_functions.query_db:68']

print('=== DATA PREVIEW ===')
print(f'MIT packages: {len(mit_packages)} items')
print(f'Project mappings: {len(project_mappings)} items')
print(f'Project info: {len(project_info)} items')
print('First MIT package:', mit_packages[0])
print('First mapping:', project_mappings[0])
print('First project info:', project_info[0])

print('\n=== PROCESSING DATA ===')
# 1. Extract all GitHub project names from project_mappings
project_names = set()
for mapping in project_mappings:
    try:
        if mapping['ProjectType'] == 'GITHUB':
            project_names.add(mapping['ProjectName'])
    except:
        pass
print(f'Found {len(project_names)} unique GitHub projects in mappings')

# 2. Extract fork counts from project_info (filter to only the projects in project_names)
fork_counts = {}
for info in project_info:
    try:
        project_info_text = str(info['Project_Information'])
        
        # Extract repo name
        repo_match = re.search(r'(?:project|repo)\s+([a-zA-Z0-9-_.]+/[a-zA-Z0-9-_.]+)', project_info_text)
        if repo_match:
            repo_name = repo_match.group(1)
            
            # Only process if it's in our project list (makes sense since info is from that same dataset)
            fork_match = re.search(r'(\d+)\s+forks', project_info_text)
            if fork_match:
                fork_count = int(fork_match.group(1))
                fork_counts[repo_name] = fork_count
    except Exception as e:
        print(f'Error processing project_info: {e}')

print(f'Extracted fork counts for {len(fork_counts)} projects')

# 3. Build a mapping of package name to GitHub project and fork count
package_fork_map = {}

# First create a lookup from package (System,Name,Version) to project name
package_to_project = {}
for mapping in project_mappings:
    try:
        if mapping['System'] == 'NPM' and mapping['ProjectType'] == 'GITHUB':
            key = (mapping['Name'], mapping['Version'])
            package_to_project[key] = mapping['ProjectName']
    except:
        pass

print(f'Created {len(package_to_project)} package-to-project mappings')

# 4. Join MIT packages with projects and fork counts
for package in mit_packages:
    try:
        package_key = (package['Name'], package['Version'])
        if package_key in package_to_project:
            project_name = package_to_project[package_key]
            if project_name in fork_counts:
                fork_count = fork_counts[project_name]
                package_fork_map[package_key] = {
                    'package': package['Name'],
                    'version': package['Version'],
                    'project': project_name,
                    'forks': fork_count
                }
    except Exception as e:
        print(f'Error processing package: {e}')

print(f'Found {len(package_fork_map)} MIT packages with fork data')

# 5. Get top 5 packages by fork count
if package_fork_map:
    top_5 = sorted(package_fork_map.values(), key=lambda x: x['forks'], reverse=True)[:5]
    print('\n=== TOP 5 NPM PACKAGES WITH HIGHEST GITHUB FORK COUNTS ===')
    for i, pkg in enumerate(top_5, 1):
        print(f'{i}. {pkg["package"]} ({pkg["version"]}) - {pkg["project"]} - {pkg["forks"]} forks')
else:
    print('No packages with fork data found')

# Output final result
result = top_5 if package_fork_map else []

print('__RESULT__:')
print(json.dumps(result))"""

